<?php
$pageTitle='Workflow Builder 2.0';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('workflow_builder_2');
$pdo=getDB();$triggers=workflowBuilderTriggerOptions();$actions=workflowBuilderActionOptions();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'rule');
    if($action==='rule'){
      $number=nextScopedDocumentNumber($pdo,'workflow_builder_rule',setting('workflow_builder_rule_prefix','WFB'),operationalScope($pdo));$user=currentUser();
      $pdo->prepare('INSERT INTO '.table('workflow_builder_rules').' (rule_number,rule_name,module,description,priority,status,run_mode,created_by) VALUES (?,?,?,?,?,?,?,?)')->execute([$number,trim((string)$_POST['rule_name']),trim((string)$_POST['module']),trim((string)$_POST['description']),(int)$_POST['priority'],trim((string)$_POST['status']),trim((string)$_POST['run_mode']),(int)($user['id']??0)?:null]);
      flash('success','Workflow rule created.');
    }elseif($action==='trigger'){
      $pdo->prepare('INSERT INTO '.table('workflow_builder_triggers').' (workflow_builder_rule_id,trigger_type,event_key,schedule_expression,source_table,status_filter,days_offset,config_json) VALUES (?,?,?,?,?,?,?,?)')->execute([(int)$_POST['rule_id'],trim((string)$_POST['trigger_type']),trim((string)$_POST['event_key']),trim((string)$_POST['schedule_expression']),trim((string)$_POST['source_table']),trim((string)$_POST['status_filter']),(int)$_POST['days_offset'],trim((string)$_POST['config_json'])?:'{}']);
      flash('success','Trigger added.');
    }elseif($action==='condition'){
      $pdo->prepare('INSERT INTO '.table('workflow_builder_conditions').' (workflow_builder_rule_id,condition_group,field_key,operator_key,compare_value,sort_order) VALUES (?,?,?,?,?,?)')->execute([(int)$_POST['rule_id'],trim((string)$_POST['condition_group']),trim((string)$_POST['field_key']),trim((string)$_POST['operator_key']),trim((string)$_POST['compare_value']),(int)$_POST['sort_order']]);
      flash('success','Condition added.');
    }elseif($action==='wf_action'){
      $pdo->prepare('INSERT INTO '.table('workflow_builder_actions').' (workflow_builder_rule_id,action_type,action_label,target_module,target_status,notification_title,notification_message,task_due_days,action_config_json,status,sort_order) VALUES (?,?,?,?,?,?,?,?,?,?,?)')->execute([(int)$_POST['rule_id'],trim((string)$_POST['action_type']),trim((string)$_POST['action_label']),trim((string)$_POST['target_module']),trim((string)$_POST['target_status']),trim((string)$_POST['notification_title']),trim((string)$_POST['notification_message']),(int)$_POST['task_due_days'],trim((string)$_POST['action_config_json'])?:'{}',trim((string)$_POST['status']),(int)$_POST['sort_order']]);
      flash('success','Action added.');
    }elseif($action==='run'){
      $result=runWorkflowBuilderRule($pdo,(int)$_POST['rule_id']);flash('success',$result['summary']);
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'workflow-builder-2']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/workflow-builder-2.php');
}
$rules=$pdo->query('SELECT * FROM '.table('workflow_builder_rules').' ORDER BY status DESC,priority DESC,created_at DESC LIMIT 200')->fetchAll();
$selected=(int)($_GET['rule_id']??($rules[0]['id']??0));
$triggerRows=[];$conditionRows=[];$actionRows=[];
if($selected){$s=$pdo->prepare('SELECT * FROM '.table('workflow_builder_triggers').' WHERE workflow_builder_rule_id=? ORDER BY id');$s->execute([$selected]);$triggerRows=$s->fetchAll();$s=$pdo->prepare('SELECT * FROM '.table('workflow_builder_conditions').' WHERE workflow_builder_rule_id=? ORDER BY sort_order,id');$s->execute([$selected]);$conditionRows=$s->fetchAll();$s=$pdo->prepare('SELECT * FROM '.table('workflow_builder_actions').' WHERE workflow_builder_rule_id=? ORDER BY sort_order,id');$s->execute([$selected]);$actionRows=$s->fetchAll();}
include dirname(__DIR__).'/header.php';
?>
