n><?php endforeach; ?></select><input class="form-control mb-2" name="schedule_expression" placeholder="daily / weekly / cron text"><input class="form-control mb-2" name="source_table" placeholder="Optional source table"><input class="form-control mb-2" name="status_filter" placeholder="Optional status"><input class="form-control mb-2" type="number" name="days_offset" value="0"><textarea class="form-control mb-3" name="config_json" rows="2">{}</textarea><button class="btn btn-outline-primary w-100">Add Trigger</button></form></div><div class="col-lg-6"><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="condition"><input type="hidden" name="rule_id" value="<?php echo (int)$selected; ?>"><h2 class="h6 mb-3">Add Condition</h2><select class="form-select mb-2" name="condition_group"><option>AND</option><option>OR</option></select><input class="form-control mb-2" name="field_key" placeholder="status / amount / age_days"><select class="form-select mb-2" name="operator_key"><option>equals</option><option>not_equals</option><option>contains</option><option>greater_than</option><option>less_than</option><option>is_not_empty</option></select><input class="form-control mb-2" name="compare_value" placeholder="Compare value"><input class="form-control mb-3" type="number" name="sort_order" value="1"><button class="btn btn-outline-primary w-100">Add Condition</button></form></div><div class="col-12"><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="wf_action"><input type="hidden" name="rule_id" value="<?php echo (int)$selected; ?>"><h2 class="h6 mb-3">Add Action</h2><div class="row g-2"><div class="col-md-4"><select class="form-select" name="action_type"><?php foreach($actions as $k=>$v): ?><option value="<?php echo esc($k); ?>"><?php echo esc($v); ?></option><?php endforeach; ?></select></div><div class="col-md-4"><input class="form-control" name="action_label" placeholder="Action label"></div><div class="col-md-4"><input class="form-control" name="target_module" placeholder="Target module"></div><div class="col-md-4"><input class="form-control" name="target_status" placeholder="Target status"></div><div class="col-md-4"><input class="form-control" name="notification_title" placeholder="Notification title"></div><div class="col-md-4"><input class="form-control" type="number" name="task_due_days" value="<?php echo (int)setting('workflow_default_task_due_days','2'); ?>"></div><div class="col-md-12"><textarea class="form-control" name="notification_message" rows="2" placeholder="Notification message"></textarea></div><div class="col-md-8"><textarea class="form-control" name="action_config_json" rows="2">{}</textarea></div><div class="col-md-2"><select class="form-select" name="status"><option>active</option><option>inactive</option></select></div><div class="col-md-2"><input class="form-control" type="number" name="sort_order" value="1"></div></div><button class="btn btn-brand mt-3">Add Action</button></form></div><div class="col-12"><div class="table-wrap table-responsive"><h2 class="h6 mb-3">Selected Rule Details</h2><div class="row"><div class="col-md-4"><strong>Triggers</strong><ul><?php foreach($triggerRows as $t): ?><li><?php echo esc($t['event_key'].' · '.$t['trigger_type']); ?></li><?php endforeach; ?></ul></div><div class="col-md-4"><strong>Conditions</strong><ul><?php foreach($conditionRows as $c): ?><li><?php echo esc($c['field_key'].' '.$c['operator_key'].' '.$c['compare_value']); ?></li><?php endforeach; ?></ul></div><div class="col-md-4"><strong>Actions</strong><ul><?php foreach($actionRows as $a): ?><li><?php echo esc($a['action_type'].' · '.$a['action_label']); ?></li><?php endforeach; ?></ul></div></div></div></div></div></div></div>
